import{_ as a,o as s,c as t,ae as l}from"./chunks/framework.BGHOrOyn.js";const i="/gitbook-personnal-docs/assets/image%20(62).NloctyZo.",n="/gitbook-personnal-docs/assets/image%20(63).CkzFaLQc.",o="/gitbook-personnal-docs/assets/image%20(64).BKxN8FlD.",r="/gitbook-personnal-docs/assets/image%20(65).DnPHJvvB.",p="/gitbook-personnal-docs/assets/image%20(66).DD14MsFx.",h="/gitbook-personnal-docs/assets/image%20(67).CSK0fc3r.",d="/gitbook-personnal-docs/assets/image%20(68).gMp30w2T.",u="/gitbook-personnal-docs/assets/image%20(69).C_TOzcwT.",c="/gitbook-personnal-docs/assets/image%20(70).CRExZiYV.",k="/gitbook-personnal-docs/assets/image%20(71).BWuAfpW7.",g="/gitbook-personnal-docs/assets/image%20(72).H2ig0CGF.",T=JSON.parse('{"title":"Cloudflare Tunnel with Docker","description":"","frontmatter":{},"headers":[],"relativePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/cloudflare-tunnel-with-docker.md","filePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/cloudflare-tunnel-with-docker.md"}'),f={name:"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/cloudflare-tunnel-with-docker.md"};function m(y,e,b,F,C,w){return s(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="cloudflare-tunnel-with-docker" tabindex="-1">Cloudflare Tunnel with Docker <a class="header-anchor" href="#cloudflare-tunnel-with-docker" aria-label="Permalink to &quot;Cloudflare Tunnel with Docker&quot;">​</a></h1><p>There’s been a few times where I needed to setup access to an internal web application but I couldn’t put it on 443 or 80 because something else was using those ports and a reverse proxy would break one of the applications. A solution to this is Cloudflare Tunnel.</p><p>Cloudflare Tunnel used to be called Warp when it was in beta and was eventually renamed to Argo Tunnel. When Cloudflare made Argo Tunnel free they renamed it to Cloudflare Tunnel. The magic of Cloudflare Tunnel is handled by a small but powerful client that is known as cloudflared.</p><p>What makes a Cloudflare Tunnel awesome is the fact that you can use it to host an application externally without opening any ports on your firewall. It does this by creating an outbound only tunnel directly to Cloudflare.</p><p>For my situation I needed to setup access to an internal web application but I didn’t want to do another port forward to make it work. My solution was Cloudflare Tunnel with Docker.</p><p>The way I set it up is slight different than what Cloudflare’s documentation says as I wanted to use the Zero Trust dashboard and Docker but also have it in a Docker Compose file, as cloudflared seems to get updated at least once a month and I wanted it to be easy enough to recreate. Here’s how I did it and how everything works.</p><h2 id="tunnel-setup" tabindex="-1">Tunnel Setup <a class="header-anchor" href="#tunnel-setup" aria-label="Permalink to &quot;Tunnel Setup&quot;">​</a></h2><ul><li>Login to Cloudflare Zero Trust Dashboard (it used to be called Cloudflare Teams): <a href="https://dash.teams.cloudflare.com/" target="_blank" rel="noreferrer">https://dash.teams.cloudflare.com/</a></li><li>Click on Access &gt; Tunnels</li></ul><p><img src="'+i+'" alt=""></p><ul><li>Click on Create a tunnel</li></ul><p><img src="'+n+'" alt=""></p><ul><li>Give your tunnel a name (example: Blog Example)</li></ul><p><img src="'+o+'" alt=""></p><h2 id="base64" tabindex="-1">Base64 <a class="header-anchor" href="#base64" aria-label="Permalink to &quot;Base64&quot;">​</a></h2><p>After saving your tunnel you are presented with the install command for cloudflared which contains a Base64 encoded string that has a lot of useful info in it that we will need.</p><p><img src="'+r+'" alt=""></p><p>Note: I altered the Base64 encoding to better show how it works.</p><ul><li>Use something like CyberChef (<a href="https://gchq.github.io/CyberChef/" target="_blank" rel="noreferrer">https://gchq.github.io/CyberChef/</a>) or another Base64 decoder to decode the install command that Cloudflare provided.</li></ul><p>This is the Base64 encoded string in my example:</p><p><code>eyJhIjoiTXlBY2NvdW50VGFnMTIzIiwidCI6Ik15VHVubmVsSUQxMjMiLCJzIjoiTXlUdW5uZWxTZWNyZXQxMjMifQ==</code></p><p>Once you decode the Base64 you will get an output that looks similar to this:</p><p><code>{&quot;a&quot;:&quot;MyAccountTag123&quot;,&quot;t&quot;:&quot;MyTunnelID123&quot;,&quot;s&quot;:&quot;MyTunnelSecret123&quot;}</code></p><p>Here is the same input and output directly on CyberChef:</p><p><a href="https://gchq.github.io/CyberChef/#recipe=From%5C_Base64(&#39;A-Za-z0-9%2B/%3D&#39;,true,false)%5C&amp;input=ZXlKaElqb2lUWGxCWTJOdmRXNTBWR0ZuTVRJeklpd2lkQ0k2SWsxNVZIVnVibVZzU1VReE1qTWlMQ0p6SWpvaVRYbFVkVzV1Wld4VFpXTnlaWFF4TWpNaWZRPT0" target="_blank" rel="noreferrer">https://gchq.github.io/CyberChef/#recipe=From\\_Base64(&#39;A-Za-z0-9%2B/%3D&#39;,true,false)\\&amp;input=ZXlKaElqb2lUWGxCWTJOdmRXNTBWR0ZuTVRJeklpd2lkQ0k2SWsxNVZIVnVibVZzU1VReE1qTWlMQ0p6SWpvaVRYbFVkVzV1Wld4VFpXTnlaWFF4TWpNaWZRPT0</a></p><ul><li>Make note of the decoded Base64 as we will need it later on.</li></ul><h2 id="urls" tabindex="-1">URLs <a class="header-anchor" href="#urls" aria-label="Permalink to &quot;URLs&quot;">​</a></h2><p>Now we need to create what the external URL will be for the web application.</p><ul><li>Enter what you want the external URL to be for the web application. Example: blogexample.thedxt.ca</li></ul><p><img src="'+p+'" alt=""></p><ul><li>Enter the internal URL for the web application. Example: <a href="http://192.168.3.41:3343" target="_blank" rel="noreferrer">http://192.168.3.41:3343</a></li></ul><p><img src="'+h+'" alt=""></p><p>You should now see your tunnel summary page.</p><p><img src="'+d+`" alt=""></p><h2 id="docker-compose-setup" tabindex="-1">Docker Compose Setup <a class="header-anchor" href="#docker-compose-setup" aria-label="Permalink to &quot;Docker Compose Setup&quot;">​</a></h2><p>This is how I like to build my Docker Compose setups — feel free to do it whichever way you prefer.</p><ul><li>Make a new folder for your Docker Compose setup (example: cloudflared-blog-example).</li><li>Make another new folder for the persistent data for the cloudflared client (example: cloudflared-example-data).</li></ul><h2 id="credentials-file" tabindex="-1">Credentials File <a class="header-anchor" href="#credentials-file" aria-label="Permalink to &quot;Credentials File&quot;">​</a></h2><p>We need to create a credentials file for cloudflared to use, using the Base64 info we decoded earlier from the cloudflared install command.</p><ul><li>In the cloudflared-example-data folder make a new JSON file named with your Tunnel ID. Example: MyTunnelID123.json</li><li>In the Tunnel ID JSON file enter your Account Tag, your Tunnel Secret and your Tunnel ID in this format:</li></ul><p><code>{&quot;AccountTag&quot;:&quot;Your Account Tag&quot;,&quot;TunnelSecret&quot;:&quot;Your Tunnel Secret&quot;,&quot;TunnelID&quot;:&quot;Your Tunnel ID&quot;}</code></p><p>Example (MyTunnelID123.json):</p><p><code>{&quot;AccountTag&quot;:&quot;MyAccountTag123&quot;,&quot;TunnelSecret&quot;:&quot;MyTunnelSecret123&quot;,&quot;TunnelID&quot;:&quot;MyTunnelID123&quot;}</code></p><p>We have just created the cloudflared credentials file.</p><h2 id="config-file" tabindex="-1">Config File <a class="header-anchor" href="#config-file" aria-label="Permalink to &quot;Config File&quot;">​</a></h2><ul><li>In the cloudflared-example-data folder create a file called config.yml</li><li>Add the following information to config.yml: <ul><li>Tunnel ID: <code>tunnel: Your Tunnel ID</code></li><li>Reference the credentials file you created earlier: <code>credentials-file: /root/.cloudflared/YourTunnelID.json</code></li></ul></li><li>Create the ingress section: <ul><li>Start with: <code>ingress:</code></li><li>Add your external hostname and the internal service mapping, for example: <ul><li>hostname: blogexample.thedxt.ca service: <a href="http://192.168.3.41:3343" target="_blank" rel="noreferrer">http://192.168.3.41:3343</a></li></ul></li><li>Add the catch-all rule to return 404 if nothing matches: <ul><li>service: http_status:404</li></ul></li></ul></li></ul><p>Example config.yml:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tunnel:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MyTunnelID123</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">credentials-file:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /root/.cloudflared/MyTunnelID123.json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ingress:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hostname:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blogexample.thedxt.ca</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     service:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://192.168.3.41:3343</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http_status:404</span></span></code></pre></div><h2 id="docker-compose-file" tabindex="-1">Docker Compose File <a class="header-anchor" href="#docker-compose-file" aria-label="Permalink to &quot;Docker Compose File&quot;">​</a></h2><p>Create docker-compose.yml in the cloudflared-blog-example folder.</p><p>Example docker-compose.yml:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;3.2&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  cloudflared-example</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cloudflare/cloudflared:2022.10.0-amd64</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    container_name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cloudflared-example</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    volumes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./cloudflared-example-data:/root/.cloudflared/</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;tunnel --config /root/.cloudflared/config.yml run&#39;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">root</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    restart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">unless-stopped</span></span></code></pre></div><ul><li>Start your Docker container.</li></ul><p>If everything is configured correctly your tunnel should now be up and showing as active in your Cloudflare Zero Trust dashboard.</p><p><img src="`+u+'" alt=""></p><p>If you check your DNS entries in Cloudflare you will see a new CNAME record pointing to YourTunnelID.cfargotunnel.com</p><p><img src="'+c+'" alt=""></p><p>Here is my internal web application running internally.</p><p><img src="'+k+'" alt=""></p><p>Now that the Cloudflare Tunnel is up and running I can reach it externally via blogexample.thedxt.ca</p><p><img src="'+g+`" alt=""></p><p>You have now just created a web application that can run without any port forwards. I think this will keep working even if you have a dynamic WAN IP, however I haven’t tested it. I suspect that if you have a dynamic WAN IP you could just stop and start your Docker container to reestablish your tunnel with your new WAN IP.</p><p>When you are ready to update your cloudflared Docker image just make sure you update the cloudflared tag as in my example I version locked it. Here is the list of Docker tags:</p><p><a href="https://hub.docker.com/r/cloudflare/cloudflared/tags" target="_blank" rel="noreferrer">https://hub.docker.com/r/cloudflare/cloudflared/tags</a></p><p>If you want to take this a step further you can also put Cloudflare Access in front of it too. If you want to know how to do that read my previous post: <a href="https://thedxt.ca/2022/06/settings-up-cloudflare-access/" target="_blank" rel="noreferrer">https://thedxt.ca/2022/06/settings-up-cloudflare-access/</a></p><h2 id="an-easier-way" tabindex="-1">An Easier Way <a class="header-anchor" href="#an-easier-way" aria-label="Permalink to &quot;An Easier Way&quot;">​</a></h2><p>An alternative approach uses the token form of the install command and avoids creating the credentials/config files manually. I’m showing both methods because the more verbose method explains how everything ties together; the token method is simpler to deploy.</p><ul><li>Make a docker-compose.yml file.</li><li>Copy the cloudflared install command — you need everything after --no-autoupdate including the Base64 token.</li></ul><p>Example docker-compose.yml using the token method:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">version:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;3.2&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">services:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   cloudflared-example:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     image:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cloudflare/cloudflared:2022.10.0-amd64</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     container_name:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Cloudflared-token</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     command</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;tunnel run --token eyJhIjoiTXlBY2NvdW50VGFnMTIzIiwidCI6Ik15VHVubmVsSUQxMjMiLCJzIjoiTXlUdW5uZWxTZWNyZXQxMjMifQ==&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     user:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     restart:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unless-stopped</span></span></code></pre></div><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li>Cloudflare Tunnel documentation: <a href="https://developers.cloudflare.com/cloudflare-one/connections/connect-apps" target="_blank" rel="noreferrer">https://developers.cloudflare.com/cloudflare-one/connections/connect-apps</a></li><li>Cloudflare cloudflared Docker tags: <a href="https://hub.docker.com/r/cloudflare/cloudflared/tags" target="_blank" rel="noreferrer">https://hub.docker.com/r/cloudflare/cloudflared/tags</a></li><li>Related post: <a href="https://thedxt.ca/2022/06/settings-up-cloudflare-access/" target="_blank" rel="noreferrer">https://thedxt.ca/2022/06/settings-up-cloudflare-access/</a></li></ul><p>Last updated 2 years ago</p>`,72)])])}const x=a(f,[["render",m]]);export{T as __pageData,x as default};
